import React, { useState, useEffect } from "react";
import { getUserFromLocalStorage } from "../utils/auth";

const Internship = () => {
  const user = getUserFromLocalStorage();
  const [internships, setInternships] = useState([]);
  const [newInternship, setNewInternship] = useState({ title: "", company: "", location: "" });

  const isAdmin = user?.role === "Admin";
  const isHR = user?.role === "HR";
  const isStudent = user?.role === "Student";

  const fetchInternships = () => {
    const stored = JSON.parse(localStorage.getItem("internships")) || [];
    setInternships(stored);
  };

  useEffect(() => {
    fetchInternships();
  }, []);

  const handleAdd = () => {
    const updated = [...internships, newInternship];
    localStorage.setItem("internships", JSON.stringify(updated));
    setNewInternship({ title: "", company: "", location: "" });
    fetchInternships();
  };

  const handleDelete = (index) => {
    const updated = internships.filter((_, i) => i !== index);
    localStorage.setItem("internships", JSON.stringify(updated));
    fetchInternships();
  };

  const handleApply = (index) => {
    alert(`Applied to: ${internships[index].title}`);
  };

  return (
    <div className="p-6">
      <h2 className="text-3xl font-bold mb-4">Internships</h2>

      {(isAdmin || isHR) && (
        <div className="mb-6 space-y-2">
          <input
            className="border px-2 py-1 w-full"
            placeholder="Title"
            value={newInternship.title}
            onChange={(e) => setNewInternship({ ...newInternship, title: e.target.value })}
          />
          <input
            className="border px-2 py-1 w-full"
            placeholder="Company"
            value={newInternship.company}
            onChange={(e) => setNewInternship({ ...newInternship, company: e.target.value })}
          />
          <input
            className="border px-2 py-1 w-full"
            placeholder="Location"
            value={newInternship.location}
            onChange={(e) => setNewInternship({ ...newInternship, location: e.target.value })}
          />
          <button className="bg-green-600 text-white px-4 py-1 rounded" onClick={handleAdd}>
            Add Internship
          </button>
        </div>
      )}

      <div className="space-y-4">
        {internships.map((intern, index) => (
          <div key={index} className="border p-4 rounded shadow-sm bg-gray-100">
            <h3 className="text-xl font-semibold">{intern.title}</h3>
            <p>{intern.company}</p>
            <p>{intern.location}</p>

            {isStudent && (
              <button
                className="mt-2 bg-blue-500 text-white px-3 py-1 rounded"
                onClick={() => handleApply(index)}
              >
                Apply
              </button>
            )}

            {isAdmin && (
              <button
                className="ml-2 mt-2 bg-red-500 text-white px-3 py-1 rounded"
                onClick={() => handleDelete(index)}
              >
                Delete
              </button>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default Internship;
